-- The frontend useGraduateAttributes hook expects columns title, code, ilo_id that don't match the actual schema. Add views or rename to align. Simplest fix: add missing columns. ALTER TABLE public.graduate_attributes ADD COLUMN IF NOT EXISTS title text; ALTER TABLE public.graduate_attributes ADD COLUMN IF NOT EXISTS code text; UPDATE public.graduate_attributes SET title = name WHERE title IS NULL; ALTER TABLE public.graduate_attribute_mappings ADD COLUMN IF NOT EXISTS ilo_id uuid; UPDATE public.graduate_attribute_mappings SET ilo_id = outcome_id WHERE ilo_id IS NULL;;
